// Core structures
interface Product {
  id: string
  code: string
  name: string
  category: string
  brand: string
  department: string
  group: string
  stock: number // maps to E. Total
  minStock: number
  price: number
  cost: number
  warehouse: string
  version: string
  priceType: string
  // Additional fields from the Windows Ficha de Producto UI:
  almPpal: number
  almSec: number
  nc: number
  comprometido: number
  iva: string // GN - GENERAL, EX - EXENTO, etc.
  uso: string
  undPrincipal: string
  fechaReferencia: string
  tCosto: string // Promedio, etc.
  tipoProducto: string // No Regulado, etc.
  procedencia: string // Nacional, etc.
  consignacion: boolean
  activo: boolean
  dctoVolumen: boolean
  tipoPromo: string
  maxCantCredito: number
  imagenUrl?: string
  descripcionAmpliada?: string
}

interface WarehouseData {
  code: string
  name: string
  activo: boolean
  lpt: string
  predestino: string
  transito: string
  tipo: string
  zona: string
  puerto: number
}

interface CategoryData {
  code: string
  name: string
  comision: number
  activo: boolean
}

interface DepartmentData {
  code: string
  name: string
  comision: number
  wpid: number
  sincro: number
}

interface GroupData {
  code: string
  name: string
  activo: boolean
  comision: number
  metaVendedor1: number
  metaVendedor2: number
  metaVendedor3: number
  metaVendedor4: number
  metaVendedor5: number
  metaVendedor6: number
  tipoMeta: string
}

interface BrandData {
  code: string
  name: string
  porcomi: number
  porcomico: number
  sincro: number
  activo: number
}

interface PriceTypeData {
  code: string
  name: string
  incIva: number // 1 = Incluye IVA, 0 = No incluye IVA
}

interface VersionData {
  code: string
  name: string
  porcomi: number
  codSada: string
}

interface AdjustmentData {
  ref: string
  date: string
  type: string
  product: string
  qty: number
  warehouse: string
  reason: string
}

interface AdjustmentItem {
  origen: string
  transaccion: string
  codigo: string
  producto: string
  uMed: string
  cantidad: number
  costo: number
  costoUsd: number
}

interface AdjustmentDoc {
  numero: string
  fecha: string
  centroCostos: string
  auxiliar: string
  almacen: string
  trans: string
  comentario: string
  contabilizado: boolean
  items: AdjustmentItem[]
}

interface PriceAdjustRow {
  id: string
  code: string
  name: string
  uMed: string
  type: string
  priceActual: number
  priceNuevo: number
  pctUtil: number
  costoOriginal: number
  stock: number
  precioOriginal: number
  priceCOP: number
  priceUSD: number
  finan: number
}

interface TransferData {
  ref: string
  date: string
  from: string
  to: string
  product: string
  qty: number
  status: string
  comentario?: string
}

