  const [activeModule, setActiveModule] = React.useState<string>("dashboard")
  const [previousModule, setPreviousModule] = React.useState<string>("dashboard")
  const [isCompanyDataOpen, setIsCompanyDataOpen] = React.useState<boolean>(false)
  const [isSearchOpen, setIsSearchOpen] = React.useState<boolean>(false)

  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === "k") {
        e.preventDefault()
        setIsSearchOpen((prev) => !prev)
      }
    }
    window.addEventListener("keydown", handleKeyDown)
    return () => window.removeEventListener("keydown", handleKeyDown)
  }, [])

  // PAGINACION DE TABLAS
  const [currentPage, setCurrentPage] = React.useState<number>(1)
  const PAGE_SIZE = 5

  React.useEffect(() => {
    setCurrentPage(1)
  }, [activeModule])

  const renderPagination = (totalItems: number) => {
    const totalPages = Math.max(1, Math.ceil(totalItems / PAGE_SIZE))
    const startRange = totalItems === 0 ? 0 : (currentPage - 1) * PAGE_SIZE + 1
    const endRange = Math.min(totalItems, currentPage * PAGE_SIZE)

    return (
      <div className="flex items-center justify-between px-4 py-3 border-t border-zinc-100 dark:border-zinc-800 bg-zinc-50/50 dark:bg-zinc-900/30">
        <span className="text-[10px] text-muted-foreground font-medium">
          Mostrando {startRange} - {endRange} de {totalItems} registros
        </span>
        <Pagination className="w-auto mx-0 select-none">
          <PaginationContent>
            <PaginationItem>
              <PaginationPrevious 
                onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                disabled={currentPage === 1 || totalItems === 0}
              />
            </PaginationItem>
            {totalPages > 1 && Array.from({ length: totalPages }).map((_, idx) => {
              const pageNum = idx + 1
              if (
                pageNum === 1 || 
                pageNum === totalPages || 
                Math.abs(pageNum - currentPage) <= 1
              ) {
                return (
                  <PaginationItem key={pageNum}>
                    <PaginationLink 
                      isActive={currentPage === pageNum}
                      onClick={() => setCurrentPage(pageNum)}
                    >
                      {pageNum}
                    </PaginationLink>
                  </PaginationItem>
                )
              } else if (
                (pageNum === 2 && currentPage > 3) || 
                (pageNum === totalPages - 1 && currentPage < totalPages - 2)
              ) {
                return (
                  <PaginationItem key={pageNum}>
                    <PaginationEllipsis />
                  </PaginationItem>
                )
              }
              return null
            })}
            {totalPages === 1 && (
              <PaginationItem>
                <PaginationLink isActive={true} onClick={() => {}} className="cursor-default pointer-events-none">
                  1
                </PaginationLink>
              </PaginationItem>
            )}
            <PaginationItem>
              <PaginationNext 
                onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                disabled={currentPage === totalPages || totalItems === 0}
              />
            </PaginationItem>
          </PaginationContent>
        </Pagination>
      </div>
    )
  }

