  const handleCreateRate = (e: React.FormEvent) => {
    e.preventDefault()
    const rateVal = parseFloat(rateForm.rate) || 0
    if (rateVal <= 0) {
      toast.error("La tasa de cambio debe ser mayor a 0")
      return
    }

    const newRate: ExchangeRateData = {
      id: String(exchangeRates.length + 1),
      date: rateForm.date,
      rate: rateVal,
      currency: rateForm.currency,
      source: rateForm.source
    }

    setExchangeRates(prev => [newRate, ...prev])
    setIsRateDialogOpen(false)
    toast.success("Nueva tasa de cambio registrada")
  }

  const handleSyncBcvRate = async () => {
    if (!token || !user || !activeBranch) return
    setIsSyncingBcv(true)
    try {
      const res = await fetch(`${API_URL}/api/data/rates/sync`, {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${token}`,
          "x-tenant-id": user.tenantId,
          "x-branch-id": activeBranch.id,
          "Content-Type": "application/json",
        }
      })
      if (res.ok) {
        const result = await res.json()
        if (result.success) {
          toast.success(result.message || "Tasa BCV sincronizada con éxito")
          // Re-fetch all rates to update local list
          const ratesRes = await fetch(`${API_URL}/api/data/rates`, {
            headers: {
              "Authorization": `Bearer ${token}`,
              "x-tenant-id": user.tenantId,
              "x-branch-id": activeBranch.id,
            }
          })
          if (ratesRes.ok) {
            const rates = await ratesRes.json()
            setExchangeRates(rates.map((r: any) => {
              const currency = r.name.includes("USD") ? "USD" : "EUR"
              const source = "Banco Central de Venezuela (BCV)"
              let dateStr = "N/A"
              if (r.bcvDate) {
                try {
                  const d = new Date(r.bcvDate)
                  dateStr = d.toLocaleDateString("es-VE", {
                    day: "2-digit",
                    month: "2-digit",
                    year: "numeric"
                  })
                } catch {
                  dateStr = r.bcvDate
                }
              } else if (r.updatedAt) {
                const d = new Date(r.updatedAt)
                dateStr = d.toLocaleDateString("es-VE", {
                  day: "2-digit",
                  month: "2-digit",
                  year: "numeric"
                })
              }
              return {
                id: r.id,
                date: dateStr,
                rate: Number(r.rate),
                currency,
                source,
                bcvDate: r.bcvDate
              }
            }))
          }
        } else {
          toast.error(result.message || "Error al sincronizar tasa")
        }
      } else {
        toast.error("Error al comunicarse con el servidor")
      }
    } catch (err: any) {
      toast.error(`Error de red: ${err.message}`)
    } finally {
      setIsSyncingBcv(false)
    }
  }

  const handleCreateInvoice = (e: React.FormEvent) => {
    e.preventDefault()
    if (!invoiceForm.docNumber) {
      toast.error("Por favor ingrese el número de factura")
      return
    }

    const sub = parseFloat(invoiceForm.subtotal) || 0
    if (sub <= 0) {
      toast.error("El subtotal debe ser mayor a 0")
      return
    }

    const supplier = suppliers.find(s => s.id === invoiceForm.supplierId)
    if (!supplier) return

    const rateObj = exchangeRates.find(r => r.id === invoiceForm.rateId)
    const rateVal = rateObj ? rateObj.rate : 36.50

    const taxVal = Math.round(sub * (parseFloat(invoiceForm.taxRate) / 100) * 100) / 100
    const totalVal = Math.round((sub + taxVal) * 100) / 100

    const newInvoice: PurchaseInvoiceData = {
      id: String(purchaseInvoices.length + 1),
      docNumber: invoiceForm.docNumber,
      supplier: supplier.name,
      date: invoiceForm.date,
      subtotal: sub,
      tax: taxVal,
      total: totalVal,
      rate: rateVal,
      status: "Pendiente"
    }

    // Update supplier balance
    setSuppliers(prev => prev.map(s => {
      if (s.id === supplier.id) {
        return { ...s, balance: s.balance + totalVal }
      }
      return s
    }))

    setPurchaseInvoices(prev => [newInvoice, ...prev])
    setIsInvoiceDialogOpen(false)
    toast.success(`Factura ${invoiceForm.docNumber} registrada con éxito. Saldo de proveedor actualizado.`)
  }

  const handleCreateOrder = (e: React.FormEvent) => {
    e.preventDefault()
    const amountVal = parseFloat(orderForm.amount) || 0
    if (amountVal <= 0) {
      toast.error("El monto estimado de la orden debe ser mayor a 0")
      return
    }

    const supplier = suppliers.find(s => s.id === orderForm.supplierId)
    if (!supplier) return

    const newOrder: PurchaseOrderData = {
      id: String(purchaseOrders.length + 1),
      ref: `OC-${Math.floor(1000 + Math.random() * 9000)}`,
      supplier: supplier.name,
      date: new Date().toISOString().split("T")[0],
      expectedDate: orderForm.expectedDate,
      amount: amountVal,
      status: "Pendiente"
    }

    setPurchaseOrders(prev => [newOrder, ...prev])
    setIsOrderDialogOpen(false)
    toast.success(`Orden de Compra ${newOrder.ref} registrada con éxito`)
  }


