  const [pdvSelectedCustomer, setPdvSelectedCustomer] = React.useState("1")
  const [pdvItems, setPdvItems] = React.useState<{ productId: string; qty: number; price: number; name: string }[]>([])
  const [pdvProductId, setPdvProductId] = React.useState("1")
  const [pdvQty, setPdvQty] = React.useState("1")

  // Ventas report state
  const [venReportGenerated, setVenReportGenerated] = React.useState(false)
  const [venReportLoading, setVenReportLoading] = React.useState(false)
  const [venReportSupplierFilter, setVenReportSupplierFilter] = React.useState("ALL")

  // Redirect if not logged in
  React.useEffect(() => {
    if (!isLoading) {
      if (!token || !user) {
        if (router) router.push("/login")
      } else if (!activeBranch) {
        if (router) router.push("/branch-selection")
      }
    }
  }, [token, user, activeBranch, isLoading, router])

  // Fetch data from backend
  React.useEffect(() => {
    if (token && user && activeBranch) {
      const fetchData = async () => {
        const checkUnauthorized = (res: Response) => {
          if (res.status === 401) {
            logout()
            return true
          }
          return false
        }

        try {
          const headers = {
            "Authorization": `Bearer ${token}`,
            "x-tenant-id": user.tenantId,
            "x-branch-id": activeBranch.id,
          }

          // 1. Fetch Products
          const productsRes = await fetch(`${API_URL}/api/data/products`, { headers })
          if (checkUnauthorized(productsRes)) return
          if (productsRes.ok) {
            const backendProducts = await productsRes.json()
            setProducts(backendProducts.map((p: any) => ({
              id: p.id,
              code: p.code,
              name: p.name,
              category: p.category,
              brand: p.brand,
              department: p.department,
              group: p.group,
              stock: Number(p.stock),
              minStock: Number(p.minStock),
              price: Number(p.price),
              cost: p.cost !== undefined && p.cost !== null ? Number(p.cost) : Number(p.price || 0) * 0.70,
              warehouse: p.warehouse,
              version: p.version,
              priceType: p.priceType,
              almPpal: 0,
              almSec: 0,
              nc: 0,
              comprometido: 0,
              iva: "GN - GENERAL",
              uso: "VENTAS",
              undPrincipal: "UND",
              fechaReferencia: "23/06/2026",
              tCosto: "Promedio",
              tipoProducto: "No Regulado",
              procedencia: "Nacional",
              consignacion: false,
              activo: true,
              dctoVolumen: false,
              tipoPromo: "Ninguno",
              maxCantCredito: 0,
              descripcionAmpliada: ""
            })))
          }

          // 2. Fetch Transactions
          const txRes = await fetch(`${API_URL}/api/data/transactions`, { headers })
          if (checkUnauthorized(txRes)) return
          if (txRes.ok) {
            const transactions = await txRes.json()
            
            const sales = transactions.filter((t: any) => t.type === "SALE")
            setSalesInvoices(sales.map((s: any) => ({
              id: s.id,
              docNumber: s.docNumber,
              customer: s.customerOrSupplierName,
              date: s.date,
              subtotal: Number(s.subtotal),
              tax: Number(s.tax),
              total: Number(s.total),
              rate: Number(s.rate),
              status: s.status,
            })))

            const purchases = transactions.filter((t: any) => t.type === "PURCHASE")
            setPurchaseInvoices(purchases.map((p: any) => ({
              id: p.id,
              docNumber: p.docNumber,
              supplier: p.customerOrSupplierName,
              date: p.date,
              subtotal: Number(p.subtotal),
              tax: Number(p.tax),
              total: Number(p.total),
              rate: Number(p.rate),
              status: p.status,
            })))
          }

          // 3. Fetch Exchange Rates
          const ratesRes = await fetch(`${API_URL}/api/data/rates`, { headers })
          if (checkUnauthorized(ratesRes)) return
          if (ratesRes.ok) {
            const rates = await ratesRes.json()
            setExchangeRates(rates.map((r: any) => {
              const currency = r.name.includes("USD") ? "USD" : "EUR"
              const source = "Banco Central de Venezuela (BCV)"
              let dateStr = "N/A"
              if (r.bcvDate) {
                try {
                  const d = new Date(r.bcvDate)
                  dateStr = d.toLocaleDateString("es-VE", {
                    day: "2-digit",
                    month: "2-digit",
                    year: "numeric"
                  })
                } catch {
                  dateStr = r.bcvDate
                }
              } else if (r.updatedAt) {
                const d = new Date(r.updatedAt)
                dateStr = d.toLocaleDateString("es-VE", {
                  day: "2-digit",
                  month: "2-digit",
                  year: "numeric"
                })
              }
              return {
                id: r.id,
                date: dateStr,
                rate: Number(r.rate),
                currency,
                source,
                bcvDate: r.bcvDate
              }
            }))
          }

          // 4. Fetch Warehouses
          const whRes = await fetch(`${API_URL}/api/data/warehouses`, { headers })
          if (checkUnauthorized(whRes)) return
          if (whRes.ok) {
            const whList = await whRes.json()
            setWarehouses(whList.map((w: any) => ({
              code: w.code,
              name: w.name,
              activo: w.isActive,
              lpt: "0",
              predestino: "",
              transito: "",
              tipo: "",
              zona: w.zona || "",
              puerto: 0
            })))
          }

          // 5. Fetch Franchises
          const franRes = await fetch(`${API_URL}/api/data/franchises`, { headers })
          if (checkUnauthorized(franRes)) return
          if (franRes.ok) {
            const franList = await franRes.json()
            setFranchises(franList.map((f: any) => ({
              id: f.id,
              code: f.code,
              name: f.name,
              zone: f.zona || "General",
              status: f.isActive ? "Activa" : "Inactiva"
            })))
          }

        } catch (error) {
          console.error("Error fetching dashboard data:", error)
        }
      }

      fetchData()
    }
  }, [token, user, activeBranch])

  // VENTAS HANDLERS
  const handleSaveCustomer = (e: React.FormEvent) => {
    e.preventDefault()
    
    // Construct RIF
    const constructedRif = customerForm.rifNumero 
      ? `${customerForm.rifLetra}-${customerForm.rifNumero}` 
      : customerForm.rif

    if (!customerForm.code || !customerForm.name || !constructedRif) {
      toast.error("Por favor complete los campos requeridos (Código, Razón Social, RIF)")
      return
    }

    const creditLim = parseFloat(customerForm.creditLimit) || 0
    const bal = parseFloat(customerForm.balance) || 0
    const isActivo = customerForm.activo && !customerForm.bloqueado
    const statusVal = isActivo ? "Activo" : "Inactivo"

    const mappedFields = {
      code: customerForm.code,
      name: customerForm.name.toUpperCase(),
      rif: constructedRif.toUpperCase(),
      phone: customerForm.phone || customerForm.celular || "",
      email: customerForm.email,
      creditLimit: creditLim,
      balance: bal,
      franchise: customerForm.franchise,
      seller: customerForm.seller,
      status: statusVal,
      tipoDoc: customerForm.tipoDoc,
      rifLetra: customerForm.rifLetra,
      rifNumero: customerForm.rifNumero,
      activo: customerForm.activo,
      bloqueado: customerForm.bloqueado,
      tipoContribuyente: customerForm.tipoContribuyente,
      tipoContribuyente2: customerForm.tipoContribuyente2,
      nombreCorto: customerForm.nombreCorto || customerForm.name.substring(0, 15).toUpperCase(),
      idWeb: customerForm.idWeb,
      pais: customerForm.pais,
      region: customerForm.region,
      estado: customerForm.estado,
      municipio: customerForm.municipio,
      parroquia: customerForm.parroquia,
      ciudad: customerForm.ciudad,
      direccion: customerForm.direccion,
      zona: customerForm.zona,
      telefono2: customerForm.telefono2,
      telefono3: customerForm.telefono3,
      celular: customerForm.celular,
      emailWeb: customerForm.emailWeb,
      codigoPostal: customerForm.codigoPostal,
      diaVisita: customerForm.diaVisita,
      comentario: customerForm.comentario
    }

    if (isCustomerEdit) {
      setCustomers(prev => prev.map(c => c.id === customerForm.id ? {
        ...c,
        ...mappedFields
      } : c))
      toast.success("Cliente actualizado con éxito")
    } else {
      const newCustomer: CustomerData = {
        id: String(customers.length + 1),
        ...mappedFields
      }
      setCustomers(prev => [...prev, newCustomer])
      toast.success("Cliente registrado con éxito")
    }
    setIsCustomerDialogOpen(false)
  }

  const handleSaveSeller = (e: React.FormEvent) => {
    e.preventDefault()
    if (!sellerForm.code || !sellerForm.name) {
      toast.error("Por favor complete los campos requeridos (Código, Nombre)")
      return
    }
    const commVal = parseFloat(sellerForm.commission) || 0
    if (isSellerEdit) {
      setSellers(prev => prev.map(s => s.id === sellerForm.id ? {
        ...s, code: sellerForm.code, name: sellerForm.name, phone: sellerForm.phone,
        email: sellerForm.email, franchise: sellerForm.franchise, commission: commVal, status: sellerForm.status
      } : s))
      toast.success("Vendedor actualizado con éxito")
    } else {
      const newSeller: SellerData = {
        id: String(sellers.length + 1), code: sellerForm.code, name: sellerForm.name,
        phone: sellerForm.phone, email: sellerForm.email, franchise: sellerForm.franchise,
        commission: commVal, status: sellerForm.status
      }
      setSellers(prev => [...prev, newSeller])
      toast.success("Vendedor registrado con éxito")
    }
    setIsSellerDialogOpen(false)
  }

  const handleCreateSalesInvoice = (e: React.FormEvent) => {
    e.preventDefault()
    if (!salesInvoiceForm.docNumber) {
      toast.error("Por favor ingrese el número de factura")
      return
    }
    const sub = parseFloat(salesInvoiceForm.subtotal) || 0
    if (sub <= 0) {
      toast.error("El subtotal debe ser mayor a 0")
      return
    }
    const customer = customers.find(c => c.id === salesInvoiceForm.customerId)
    if (!customer) return
    const rateObj = exchangeRates.find(r => r.id === salesInvoiceForm.rateId)
    const rateVal = rateObj ? rateObj.rate : 36.50
    const taxVal = Math.round(sub * (parseFloat(salesInvoiceForm.taxRate) / 100) * 100) / 100
    const totalVal = Math.round((sub + taxVal) * 100) / 100

    const newInv: SalesInvoiceData = {
      id: String(salesInvoices.length + 1), docNumber: salesInvoiceForm.docNumber,
      customer: customer.name, date: salesInvoiceForm.date,
      subtotal: sub, tax: taxVal, total: totalVal, rate: rateVal, status: "Pendiente"
    }
    // Update customer CxC balance
    setCustomers(prev => prev.map(c => c.id === customer.id ? { ...c, balance: c.balance + totalVal } : c))
    setSalesInvoices(prev => [newInv, ...prev])
    setIsSalesInvoiceDialogOpen(false)
    toast.success(`Factura ${salesInvoiceForm.docNumber} registrada. Saldo CxC del cliente actualizado.`)
  }

  const handleCreateSalesQuote = (e: React.FormEvent) => {
    e.preventDefault()
    const totalVal = parseFloat(salesQuoteForm.total) || 0
    if (totalVal <= 0) { toast.error("El total de la cotización debe ser mayor a 0"); return }
    const customer = customers.find(c => c.id === salesQuoteForm.customerId)
    if (!customer) return
    const validDate = new Date()
    validDate.setDate(validDate.getDate() + parseInt(salesQuoteForm.validDays))
    const newQuote: SalesQuoteData = {
      id: String(salesQuotes.length + 1),
      ref: `COT-${Math.floor(100 + Math.random() * 900)}`,
      customer: customer.name, date: salesQuoteForm.date,
      validUntil: validDate.toISOString().split("T")[0],
      total: totalVal, status: "Vigente"
    }
    setSalesQuotes(prev => [newQuote, ...prev])
    setIsSalesQuoteDialogOpen(false)
    toast.success(`Cotización ${newQuote.ref} generada con éxito`)
  }

  const handleCreateSalesOrder = (e: React.FormEvent) => {
    e.preventDefault()
    const totalVal = parseFloat(salesOrderForm.total) || 0
    if (totalVal <= 0) { toast.error("El total del pedido debe ser mayor a 0"); return }
    const customer = customers.find(c => c.id === salesOrderForm.customerId)
    if (!customer) return
    const newOrder: SalesOrderData = {
      id: String(salesOrders.length + 1),
      ref: `PED-${Math.floor(1000 + Math.random() * 9000)}`,
      customer: customer.name, date: new Date().toISOString().split("T")[0],
      expectedDate: salesOrderForm.expectedDate, total: totalVal, status: "Pendiente"
    }
    setSalesOrders(prev => [newOrder, ...prev])
    setIsSalesOrderDialogOpen(false)
    toast.success(`Pedido ${newOrder.ref} registrado con éxito`)
  }

  const handlePdvAddItem = () => {
    const product = products.find(p => p.id === pdvProductId)
    if (!product) return
    const qty = parseInt(pdvQty) || 1
    if (qty <= 0) { toast.error("Cantidad inválida"); return }
    const existing = pdvItems.findIndex(i => i.productId === pdvProductId)
    if (existing >= 0) {
      setPdvItems(prev => prev.map((item, idx) => idx === existing ? { ...item, qty: item.qty + qty } : item))
    } else {
      setPdvItems(prev => [...prev, { productId: product.id, name: product.name, price: product.price, qty }])
    }
    setPdvQty("1")
  }

  const handlePdvCheckout = () => {
    if (pdvItems.length === 0) { toast.error("Agregue productos al carrito primero"); return }
    const customer = customers.find(c => c.id === pdvSelectedCustomer)
    if (!customer) return
    const totalVal = pdvItems.reduce((acc, i) => acc + i.price * i.qty, 0)
    const taxVal = Math.round(totalVal * 0.16 * 100) / 100
    const grandTotal = Math.round((totalVal + taxVal) * 100) / 100
    const docNum = `PDV-${Math.floor(10000 + Math.random() * 90000)}`
    const newInv: SalesInvoiceData = {
      id: String(salesInvoices.length + 1), docNumber: docNum,
      customer: customer.name, date: new Date().toISOString().split("T")[0],
      subtotal: totalVal, tax: taxVal, total: grandTotal,
      rate: exchangeRates[0]?.rate ?? 36.50, status: "Pendiente"
    }
    setCustomers(prev => prev.map(c => c.id === customer.id ? { ...c, balance: c.balance + grandTotal } : c))
    setSalesInvoices(prev => [newInv, ...prev])
    setPdvItems([])
    toast.success(`Venta ${docNum} procesada — Total: $${grandTotal.toFixed(2)}`)
  }

  const handleGenerateVenReport = () => {
    setVenReportLoading(true)
    setVenReportGenerated(false)
    setTimeout(() => {
      setVenReportLoading(false)
      setVenReportGenerated(true)
      toast.success("Informe de Ventas generado correctamente")
    }, 600)
  }


