  // FINANZAS HANDLERS
  const handleCreateDeposit = (e: React.FormEvent) => {
    e.preventDefault()
    const amt = parseFloat(depositForm.amount) || 0
    if (amt <= 0) { toast.error("El monto del depósito debe ser mayor a 0"); return }
    const bank = companyBanks.find(b => b.id === depositForm.bankAccountId)
    if (!bank) return
    const newDep: BankDepositData = {
      id: String(bankDeposits.length + 1),
      ref: `DEP-${String(bankDeposits.length + 84).padStart(4, "0")}`,
      bankAccount: `${bank.bankName} — ${bank.accountNumber}`,
      date: depositForm.date, amount: amt, currency: depositForm.currency,
      description: depositForm.description, status: "Pendiente"
    }
    // Update bank balance
    setCompanyBanks(prev => prev.map(b => b.id === bank.id ? { ...b, balance: b.balance + amt } : b))
    setBankDeposits(prev => [newDep, ...prev])
    setIsDepositDialogOpen(false)
    toast.success(`Depósito ${newDep.ref} registrado. Saldo bancario actualizado.`)
  }

  const handleCreateBankTransfer = (e: React.FormEvent) => {
    e.preventDefault()
    const amt = parseFloat(transferForm.amount) || 0
    if (amt <= 0) { toast.error("El monto de la transferencia debe ser mayor a 0"); return }
    if (transferForm.fromAccountId === transferForm.toAccountId) { toast.error("Las cuentas origen y destino deben ser diferentes"); return }
    const fromBank = companyBanks.find(b => b.id === transferForm.fromAccountId)
    const toBank = companyBanks.find(b => b.id === transferForm.toAccountId)
    if (!fromBank || !toBank) return
    const newTrf: BankTransferData = {
      id: String(bankTransfers.length + 1),
      ref: `TRF-${String(bankTransfers.length + 13).padStart(4, "0")}`,
      fromAccount: `${fromBank.bankName} — ${fromBank.accountType} ${fromBank.currency}`,
      toAccount: `${toBank.bankName} — ${toBank.accountType} ${toBank.currency}`,
      date: transferForm.date, amount: amt, currency: transferForm.currency, status: "Pendiente"
    }
    setCompanyBanks(prev => prev.map(b => {
      if (b.id === fromBank.id) return { ...b, balance: b.balance - amt }
      if (b.id === toBank.id) return { ...b, balance: b.balance + amt }
      return b
    }))
    setBankTransfers(prev => [newTrf, ...prev])
    setIsTransferDialogOpen(false)
    toast.success(`Transferencia ${newTrf.ref} registrada. Saldos actualizados.`)
  }

  const handleCreateVoucher = (e: React.FormEvent) => {
    e.preventDefault()
    const amt = parseFloat(voucherForm.amount) || 0
    if (amt <= 0) { toast.error("El monto del comprobante debe ser mayor a 0"); return }
    const supplier = suppliers.find(s => s.id === voucherForm.supplierId)
    const bank = companyBanks.find(b => b.id === voucherForm.bankAccountId)
    if (!supplier || !bank) return
    const nextSeries = paymentSeries[0]
    const newVoucher: PaymentVoucherData = {
      id: String(paymentVouchers.length + 1),
      ref: `${nextSeries.series}-${String(nextSeries.nextNumber).padStart(4, "0")}`,
      supplierName: supplier.name, date: voucherForm.date,
      amount: amt, currency: voucherForm.currency,
      paymentMethod: voucherForm.paymentMethod, bankAccount: bank.bankName, status: "Pendiente"
    }
    // Deduct from bank & reduce supplier CxP balance
    setCompanyBanks(prev => prev.map(b => b.id === bank.id ? { ...b, balance: b.balance - amt } : b))
    setSuppliers(prev => prev.map(s => s.id === supplier.id ? { ...s, balance: Math.max(0, s.balance - amt) } : s))
    setPaymentVouchers(prev => [newVoucher, ...prev])
    setIsVoucherDialogOpen(false)
    toast.success(`Comprobante ${newVoucher.ref} emitido. CxP y saldo bancario actualizados.`)
  }

  const handleCreateReceipt = (e: React.FormEvent) => {
    e.preventDefault()
    const amt = parseFloat(receiptForm.amount) || 0
    if (amt <= 0) { toast.error("El monto del recibo debe ser mayor a 0"); return }
    const customer = customers.find(c => c.id === receiptForm.customerId)
    const bank = companyBanks.find(b => b.id === receiptForm.bankAccountId)
    if (!customer || !bank) return
    const nextSeries = receiptSeries[0]
    const newReceipt: IncomeReceiptData = {
      id: String(incomeReceipts.length + 1),
      ref: `${nextSeries.series}-${String(nextSeries.nextNumber).padStart(4, "0")}`,
      customerName: customer.name, date: receiptForm.date,
      amount: amt, currency: receiptForm.currency,
      concept: receiptForm.concept, bankAccount: bank.bankName, status: "Aplicado",
      tipoCobro: receiptForm.tipoCobro,
      referencia: receiptForm.referencia,
      selectedCuotaId: receiptForm.selectedCuotaId,
    }

    // If initial payment (Cuota 0) is loaded, activate the pending contract:
    if (receiptForm.selectedCuotaId === "0") {
      const pendingContractIndex = creditContracts.findIndex(x => x.customer === customer.name && x.status === "PENDIENTE")
      if (pendingContractIndex !== -1) {
        setCreditContracts(prev => prev.map((x, idx) => idx === pendingContractIndex ? { ...x, status: "VIGENTE" } : x))
        toast.info(`Contrato ${creditContracts[pendingContractIndex].ref} activado a VIGENTE tras recibir la cuota inicial.`)
      }
    }

    // Credit bank balance & reduce customer CxC
    setCompanyBanks(prev => prev.map(b => b.id === bank.id ? { ...b, balance: b.balance + amt } : b))
    setCustomers(prev => prev.map(c => c.id === customer.id ? { ...c, balance: Math.max(0, c.balance - amt) } : c))
    setIncomeReceipts(prev => [newReceipt, ...prev])
    setIsReceiptDialogOpen(false)
    toast.success(`Recibo ${newReceipt.ref} registrado. CxC y saldo bancario actualizados.`)
  }

