  // Dynamic metrics for the Dashboard based on real state data
  const dashboardMetrics = React.useMemo(() => {
    const ventas = salesInvoices.reduce((sum, inv) => sum + inv.total, 0)
    const compras = purchaseInvoices.reduce((sum, inv) => sum + inv.total, 0)
    const cxc = salesInvoices.filter(inv => inv.status === "Pendiente").reduce((sum, inv) => sum + inv.total, 0)
    const cxp = suppliers.reduce((sum, s) => sum + s.balance, 0)
    const productosVal = products.reduce((sum, p) => sum + (p.stock * p.price), 0)
    const stockTotal = products.reduce((sum, p) => sum + p.stock, 0)
    const usdBank = companyBanks.filter(b => b.currency === "USD").reduce((sum, b) => sum + b.balance, 0)
    const bsBank = companyBanks.filter(b => b.currency === "Bs").reduce((sum, b) => sum + b.balance, 0)

    return {
      ventas,
      compras,
      cxc,
      cxp,
      productosVal,
      stockTotal,
      usdBank,
      bsBank,
    }
  }, [salesInvoices, purchaseInvoices, suppliers, products, companyBanks])

  // Group sales and purchases by date for the Chart
  const dashboardChartData = React.useMemo(() => {
    const dates = ["2026-06-15", "2026-06-18", "2026-06-19", "2026-06-20", "2026-06-21", "2026-06-22", "2026-06-23"]
    return dates.map(date => {
      const sales = salesInvoices
        .filter(inv => inv.date === date)
        .reduce((sum, inv) => sum + inv.total, 0)
      const purchases = purchaseInvoices
        .filter(inv => inv.date === date)
        .reduce((sum, inv) => sum + inv.total, 0)
      
      const formattedDate = new Date(date + "T00:00:00").toLocaleDateString("es-VE", {
        day: "numeric",
        month: "short"
      })
      
      return {
        name: formattedDate,
        Ventas: sales,
        Compras: purchases
      }
    })
  }, [salesInvoices, purchaseInvoices])

