                    municipio: s.municipio || "SAN CRISTOBAL",
                    direccion: s.direccion || "",
                    zona: s.zona || "",
                    telefono2: s.telefono2 || "",
                    telefono3: s.telefono3 || "",
                    celular: s.celular || "",
                    codigoPostal: s.codigoPostal || "",
