                      creditLimit: "5000.00", balance: "0.00",
                      franchise: "Franquicia Norte", seller: "Juan García", status: "Activo",
                      tipoDoc: "RIF", rifLetra: "J", rifNumero: "",
                      activo: true, bloqueado: false,
                      tipoContribuyente: "JURIDICO", tipoContribuyente2: "ORDINARIO",
